function slugify(name) {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 80);
}

const PRODUCTS_WITH_SLUGS = PRODUCTS.map(p => ({
  ...p,
  slug: slugify(p.name),
  research: RESEARCH[p.id] || null,
}));

module.exports = { PRODUCTS, PRODUCTS_WITH_SLUGS, RESEARCH, CATS, DISC, slugify };
